{
 "level": "A1–A2",
 "intro": "In this topic you will learn <strong>four basic sentence types</strong> in English: statements, negatives, questions and imperatives, plus their core word order.",
 "rules": [
 {
 "label": "Affirmative",
 "color": "emerald",
 "text": "<strong>Affirmative</strong> — state the fact:",
 "example": "She reads books."
 },
 {
 "label": "Negative",
 "color": "rose",
 "text": "<strong>Negative</strong> — deny the action:",
 "example": "She does not read books."
 },
 {
 "label": "Interrogative",
 "color": "blue",
 "text": "Use the pattern in the examples and focus on the highlighted words.",
 "example": "Does she read books?"
 },
 {
 "label": "Imperative",
 "color": "amber",
 "text": "Use the pattern in the examples and focus on the highlighted words.",
 "example": "Read this book!"
 }
 ]
}

{
 "title": "1. Overview of the four types of sentences here.)",
 "intro": "English sentences can be grouped into four types by purpose:",
 "items": [
 {
 "label": "Affirmative",
 "title": "Affirmative sentence",
 "subtitle": "Grammar focus"
 },
 {
 "label": "Negative",
 "title": "Negative",
 "subtitle": "Denys a fact or action (She does not work here.)"
 },
 {
 "label": "Interrogative",
 "title": "Interrogative",
 "subtitle": "Ask a question (Does she work here?)"
 },
 {
 "label": "Imperative",
 "title": "Imperative",
 "subtitle": "Expresses an order, request, advice (Work harder!)"
 }
 ]
}

{
 "title": "2. Affirmative Sentences",
 "sections": [
 {
 "label": "Structure",
 "color": "emerald",
 "description": "An affirmative sentence states a fact. Structure: <strong>Subject + Verb + Object</strong>.",
 "examples": [
 {
 "en": "I like coffee.",
 "ua": "I like coffee."
 },
 {
 "en": "She works at a hospital.",
 "ua": "She works at a hospital."
 },
 {
 "en": "They have two children.",
 "ua": "They have two children."
 }
 ]
 },
 {
 "label": "With the verb TO BE",
 "color": "sky",
 "description": "With the verb <strong>to be</strong> structure: <strong>Subject + am/is/are + Complement</strong>.",
 "examples": [
 {
 "en": "I am a student.",
 "ua": "I am a student."
 },
 {
 "en": "She is happy: the east.",
 "ua": "She is happy: the east."
 },
 {
 "en": "They are at home.",
 "ua": "They are at home."
 }
 ]
 },
 {
 "label": "Punctuation",
 "color": "amber",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": {
 "en": "The sun rises in the east.",
 "ua": "The sun rises in the east."
 }
 }
 ]
}

{
 "title": "3. Negative Sentences - Negative sentences",
 "sections": [
 {
 "label": "With an auxiliary verb",
 "color": "emerald",
 "description": "To negate, add <strong>do/does/did + not</strong> before the main verb.",
 "examples": [
 {
 "en": "I do not like coffee.",
 "ua": "I do not like coffee."
 },
 {
 "en": "She does not work here: <strong>am/is/are + not</strong>.",
 "ua": "She does not work here: <strong>am/is/are + not</strong>."
 },
 {
 "en": "They did not come yesterday.",
 "ua": "They did not come yesterday."
 }
 ]
 },
 {
 "label": "With the verb TO BE",
 "color": "sky",
 "description": "With the verb <strong>to be</strong>, put <strong>not</strong> after it: <strong>am/is/are + not</strong>.",
 "examples": [
 {
 "en": "I am not tired.",
 "ua": "I am not tired."
 },
 {
 "en": "She is not at home.",
 "ua": "She is not at home."
 },
 {
 "en": "They are not ready.",
 "ua": "They are not ready."
 }
 ]
 },
 {
 "label": "Short forms",
 "color": "amber",
 "description": "In colloquial language <strong>abbreviations</strong> are often used.",
 "examples": [
 {
 "en": "don't = do not",
 "ua": "don't = do not"
 },
 {
 "en": "doesn't = does not",
 "ua": "doesn't = does not"
 },
 {
 "en": "isn't = is not",
 "ua": "isn't = is not"
 },
 {
 "en": "aren't = are not",
 "ua": "aren't = are not"
 }
 ]
 }
 ]
}

{
 "title": "4. Interrogative Sentences - Interrogative sentences",
 "sections": [
 {
 "label": "Yes/No Questions",
 "color": "emerald",
 "description": "General questions (answer Yes/No). Structure: Do/Does/Did + Subject + Verb? yesterday?",
 "examples": [
 {
 "en": "Do you like coffee?",
 "ua": "Do you like coffee?"
 },
 {
 "en": "Does she work here?",
 "ua": "Does she work here?"
 },
 {
 "en": "Did they come yesterday?",
 "ua": "Did they come yesterday?"
 }
 ]
 },
 {
 "label": "Question with TO BE",
 "color": "sky",
 "description": "With the verb <strong>to be</strong> it comes first: <strong>Am/Is/Are + Subject?</strong>",
 "examples": [
 {
 "en": "Are you ready?",
 "ua": "Are you ready?"
 },
 {
 "en": "Is she a doctor?",
 "ua": "Is she a doctor?"
 },
 {
 "en": "Were they at the party?",
 "ua": "Were they at the party?"
 }
 ]
 },
 {
 "label": "Wh-Questions",
 "color": "amber",
 "description": "Special questions with question words: <strong>What, Where, When, Why, Who, How</strong>.",
 "examples": [
 {
 "en": "What do you do?",
 "ua": "What do you do?"
 },
 {
 "en": "Where does she live?",
 "ua": "Where does she live?"
 },
 {
 "en": " Why are you late? Imperative Sentences - Imperative Sentences",
 "ua": " Why are you late? Imperative Sentences - Imperative Sentences"
 },
 {
 "en": "How did they get there?",
 "ua": "How did they get there?"
 }
 ],
 "note": "Use the pattern in the examples and focus on the highlighted words."
 }
 ]
}

{
 "title": "5. Imperative Sentences",
 "sections": [
 {
 "label": "Structure",
 "color": "emerald",
 "description": "An imperative sentence expresses a command, request, or advice. Begins with <strong>verb in base form</strong>, without subject.",
 "examples": [
 {
 "en": "Open the door.",
 "ua": "Open the door."
 },
 {
 "en": "Come here.",
 "ua": "Come here."
 },
 {
 "en": "Be quiet.",
 "ua": "Be quiet."
 }
 ]
 },
 {
 "label": "Negative form",
 "color": "sky",
 "description": "For a negative command, we use <strong>Do not (Don't) + Verb</strong>.",
 "examples": [
 {
 "en": "Don't touch that!",
 "ua": "Don't touch that!"
 },
 {
 "en": "Don't be late.",
 "ua": "Don't be late."
 },
 {
 "en": "Don't forget your keys.",
 "ua": "Don't forget your keys."
 }
 ]
 },
 {
 "label": "Polite forms",
 "color": "amber",
 "description": "To be polite, add <strong>please</strong> or use <strong>Let's</strong> for suggestions.",
 "examples": [
 {
 "en": "Please sit down.",
 "ua": "Please sit down."
 },
 {
 "en": "Please be patient.",
 "ua": "Please be patient."
 },
 {
 "en": "Let's go to the cinema.",
 "ua": "Let's go to the cinema."
 },
 {
 "en": "Let's start the meeting.",
 "ua": "Let's start the meeting."
 }
 ],
 "note": "An imperative sentence can end with a <strong>period (.)</strong> or an <strong>exclamation mark (!)</strong>."
 }
 ]
}

{
 "title": "6. Comparative table of structures",
 "intro": "Structures of four types of sentences:",
 "rows": [
 {
 "en": "Affirmative",
 "ua": "Affirmative",
 "note": "S + V + O → She reads books."
 },
 {
 "en": "Negative",
 "ua": "Negative",
 "note": "S + do/does + not + V → She doesn't read."
 },
 {
 "en": "Interrogative",
 "ua": "Interrogative",
 "note": "Do/Does + S + V? → Does he read? (do/does/did)!"
 },
 {
 "en": "Imperative",
 "ua": "Imperative",
 "note": "V + O → Read this book!"
 }
 ],
 "warning": "Use the pattern in the examples and focus on the highlighted words."
}

{
 "title": "7. Punctuation of different types of sentences",
 "intro": "Each type of sentence has its own punctuation mark:",
 "rows": [
 {
 "en": "Affirmative",
 "ua": "Affirmative",
 "note": "Dot (.) — She is a teacher."
 },
 {
 "en": "Negative",
 "ua": "Negative",
 "note": "Dot (.) — She is not a teacher."
 },
 {
 "en": "Interrogative",
 "ua": "Interrogative",
 "note": "Question mark (?) — Is she a teacher?"
 },
 {
 "en": "Imperative",
 "ua": "Imperative",
 "note": "Dot (.) or exclamation mark (!) — Be quiet! / Be quiet."
 }
 ]
}

{
 "title": "8. Common mistakes",
 "items": [
 {
 "label": "Error 1",
 "color": "rose",
 "title": "Omission of an auxiliary verb in negatives.",
 "wrong": "She not likes coffee.",
 "right": "​​​​ <span class=\"font-mono\">She does not like coffee.</span>"
 },
 {
 "label": "Error 2",
 "color": "amber",
 "title": "Omission of auxiliary verb in questions.",
 "wrong": "You like coffee?",
 "right": "​​​​​​​​ coffee?</span>"
 },
 {
 "label": "Mistake 3",
 "color": "sky",
 "title": "Adding -s after does.",
 "wrong": "Does she likes coffee?",
 "right": "✅ <span class=\"font-mono\">Does she like coffee?</span>"
 },
 {
 "label": "Error 4",
 "color": "purple",
 "title": "Subject in an imperative sentence.",
 "wrong": "You open the door!",
 "right": " ✅ <span class=\"font-mono\">Open the door!</span>"
 }
 ]
}

{
 "title": "10. Practice",
 "select_title": "Exercise 1. Determine the type of sentence",
 "select_intro": "Determine what type the sentence belongs to.",
 "selects": [
 {
 "label": "She works at a bank. (Affirmative / Negative / Interrogative / Imperative)",
 "prompt": "What type?"
 },
 {
 "label": "Do you speak English? (Affirmative / Negative / Interrogative / Imperative)",
 "prompt": "What type?"
 },
 {
 "label": "Close the window. (Affirmative / Negative / Interrogative / Imperative)",
 "prompt": "What type?"
 },
 {
 "label": "I don't understand. (Affirmative / Negative / Interrogative / Imperative)",
 "prompt": "What type?"
 }
 ],
 "options": [
 "Affirmative",
 "Negative",
 "Interrogative",
 "Imperative"
 ],
 "input_title": "Exercise 2. Convert sentence",
 "input_intro": "Turn the affirmative sentence into other types.",
 "inputs": [
 {
 "before": "She likes music. → Negative:",
 "after": "→"
 },
 {
 "before": "She likes music. → Question:",
 "after": "→"
 },
 {
 "before": "You are quiet. → Imperative:",
 "after": "→"
 }
 ],
 "rephrase_title": "Exercise 3. Error correction",
 "rephrase_intro": "Find and correct the error in the sentence.",
 "rephrase": [
 {
 "example_label": "Example:",
 "example_original": "She doesn't like coffee.",
 "example_target": "She doesn't like coffee."
 },
 {
 "original": "1. Does he like football?",
 "placeholder": "Fix the error"
 },
 {
 "original": "2. You be quiet!",
 "placeholder": "Correct an error"
 }
 ]
}

